import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { calculateWPM, calculateAccuracy, formatTime, generateRaceId } from '../utils/typingEngine';
import { sampleText, createAutoChallenges } from '../utils/mockData';
import { submitRaceResult } from '../utils/typingApi';
import '../styles/Play.css';

export default function Play() {
  const navigate = useNavigate();
  const [raceMode, setRaceMode] = useState('mode-select');
  const [selectedDuration, setSelectedDuration] = useState(60);
  const [displayText, setDisplayText] = useState(sampleText);
  const [challenges, setChallenges] = useState([]);
  const [selectedChallengeId, setSelectedChallengeId] = useState(null);
  const [selectedChallenge, setSelectedChallenge] = useState(null);
  const [typedText, setTypedText] = useState('');
  const [timeLeft, setTimeLeft] = useState(selectedDuration);
  const [isRacing, setIsRacing] = useState(false);
  const [raceData, setRaceData] = useState(null);
  const inputRef = useRef(null);
  const timerRef = useRef(null);

  useEffect(() => {
    const generatedChallenges = createAutoChallenges(6);
    setChallenges(generatedChallenges);

    if (generatedChallenges.length) {
      setSelectedChallengeId(generatedChallenges[0].id);
      setSelectedChallenge(generatedChallenges[0]);
      setDisplayText(generatedChallenges[0].prompt);
    }
  }, []);

  const refreshChallenges = () => {
    const generatedChallenges = createAutoChallenges(6);
    setChallenges(generatedChallenges);

    if (generatedChallenges.length) {
      setSelectedChallengeId(generatedChallenges[0].id);
      setSelectedChallenge(generatedChallenges[0]);
      setDisplayText(generatedChallenges[0].prompt);
    }
  };

  const selectChallenge = (challenge) => {
    setSelectedChallengeId(challenge.id);
    setSelectedChallenge(challenge);
    setDisplayText(challenge.prompt);
    startRace(selectedDuration, challenge);
  };

  const startRace = (duration, challengeOverride = null) => {
    const challengeToUse = challengeOverride || selectedChallenge;
    if (!challengeToUse) return;

    setSelectedDuration(duration);
    setTimeLeft(duration);
    setSelectedChallenge(challengeToUse);
    setDisplayText(challengeToUse.prompt);
    setTypedText('');
    setRaceMode('racing');
    setIsRacing(true);
    setTimeout(() => inputRef.current?.focus(), 100);
  };

  const endRace = useCallback(async () => {
    setIsRacing(false);
    clearInterval(timerRef.current);

    const elapsed = selectedDuration - timeLeft;
    const wpm = calculateWPM(typedText, elapsed);
    const accuracy = calculateAccuracy(displayText, typedText);
    const netWPM = Math.max(0, wpm - (((100 - accuracy) / 100) * wpm));

    const finalData = {
      id: generateRaceId(),
      wpm: Math.round(wpm * 10) / 10,
      netWPM: Math.round(netWPM * 10) / 10,
      accuracy,
      duration: selectedDuration,
      timestamp: new Date(),
      typedChars: typedText.length,
      challengeTitle: selectedChallenge?.title ?? 'Custom Challenge',
      targetWpm: selectedChallenge?.targetWpm ?? null,
    };

    try {
      await submitRaceResult(finalData);
      setRaceData(finalData);
      setRaceMode('complete');
    } catch (error) {
      console.error('Error submitting race:', error);
      setRaceData(finalData);
      setRaceMode('complete');
    }
  }, [displayText, selectedChallenge, selectedDuration, timeLeft, typedText]);

  useEffect(() => {
    if (raceMode === 'racing' && isRacing && timeLeft > 0) {
      timerRef.current = setInterval(() => {
        setTimeLeft((t) => t - 1);
      }, 1000);
    } else if (timeLeft === 0 && isRacing) {
      endRace();
    }

    return () => clearInterval(timerRef.current);
  }, [endRace, isRacing, raceMode, timeLeft]);

  const resetRace = () => {
    setTypedText('');
    setTimeLeft(selectedDuration);
    setRaceMode('mode-select');
    setRaceData(null);
  };

  const handleInputChange = (e) => {
    if (isRacing) {
      setTypedText(e.target.value);
    }
  };

  const currentWPM = isRacing ? calculateWPM(typedText, selectedDuration - timeLeft) : 0;
  const currentAccuracy = isRacing ? calculateAccuracy(displayText, typedText) : 0;

  return (
    <div className="play-container">
      {raceMode === 'mode-select' && (
        <div className="mode-select">
          <h1>Choose Your Challenge</h1>

          <div className="challenge-toolbar">
            <h2>Auto-generated typing challenges</h2>
            <div className="challenge-toolbar__actions">
              <div className="duration-switch">
                <button
                  className={`duration-switch__btn ${selectedDuration === 30 ? 'active' : ''}`}
                  onClick={() => setSelectedDuration(30)}
                >
                  30s
                </button>
                <button
                  className={`duration-switch__btn ${selectedDuration === 60 ? 'active' : ''}`}
                  onClick={() => setSelectedDuration(60)}
                >
                  60s
                </button>
                <button
                  className={`duration-switch__btn ${selectedDuration === 120 ? 'active' : ''}`}
                  onClick={() => setSelectedDuration(120)}
                >
                  120s
                </button>
              </div>
              <button className="btn btn-outline-primary" onClick={refreshChallenges}>
                Refresh Challenges
              </button>
            </div>
          </div>

          <div className="challenge-grid">
            {challenges.map((challenge) => (
              <button
                key={challenge.id}
                className={`challenge-card ${selectedChallengeId === challenge.id ? 'active' : ''}`}
                onClick={() => selectChallenge(challenge)}
              >
                <div className="challenge-card__top">
                  <h3>{challenge.title}</h3>
                  <span className="challenge-difficulty">{challenge.difficulty}</span>
                </div>
                <p>{challenge.prompt}</p>
                <div className="challenge-meta">
                  <span>Target: {challenge.targetWpm} WPM</span>
                  <span>{challenge.estimatedChars} chars</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      )}

      {raceMode === 'racing' && (
        <div className="race-arena">
          <div className="race-header">
            <div className="stats">
              <div className="stat">
                <span className="stat-label">WPM</span>
                <span className="stat-value">{Math.round(currentWPM)}</span>
              </div>
              <div className="stat">
                <span className="stat-label">Accuracy</span>
                <span className="stat-value">{Math.round(currentAccuracy)}%</span>
              </div>
              <div className="timer">
                <span className={`time ${timeLeft <= 10 ? 'danger' : ''}`}>{formatTime(timeLeft)}</span>
              </div>
            </div>
          </div>

          <div className="typing-area">
            <div className="display-text">
              {displayText.split('').map((char, idx) => {
                let charClass = 'char untyped';
                if (idx < typedText.length) {
                  charClass = typedText[idx] === char ? 'char correct' : 'char incorrect';
                }
                return (
                  <span key={idx} className={charClass}>
                    {char}
                  </span>
                );
              })}
            </div>

            <textarea
              ref={inputRef}
              className="typing-input"
              value={typedText}
              onChange={handleInputChange}
              placeholder="Start typing here..."
              disabled={!isRacing}
            />
          </div>

          <button className="btn btn-danger" onClick={endRace}>
            Finish Race
          </button>
        </div>
      )}

      {raceMode === 'complete' && raceData && (
        <div className="race-results">
          <h1>Race Complete!</h1>
          <p className="results-challenge">
            Challenge: <strong>{raceData.challengeTitle}</strong>
            {raceData.targetWpm ? ` | Target ${raceData.targetWpm} WPM` : ''}
          </p>

          <div className="results-grid">
            <div className="result-card">
              <span className="result-label">WPM</span>
              <span className="result-value">{raceData.wpm}</span>
            </div>
            <div className="result-card">
              <span className="result-label">Net WPM</span>
              <span className="result-value">{raceData.netWPM}</span>
            </div>
            <div className="result-card">
              <span className="result-label">Accuracy</span>
              <span className="result-value">{raceData.accuracy.toFixed(1)}%</span>
            </div>
            <div className="result-card">
              <span className="result-label">Characters</span>
              <span className="result-value">{raceData.typedChars}</span>
            </div>
          </div>

          <div className="results-actions">
            <button className="btn btn-primary" onClick={resetRace}>
              Race Again
            </button>
            <button className="btn btn-secondary" onClick={() => navigate('/leaderboard')}>
              View Leaderboard
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
